const ctx = {
  workflow_name: 'example-mock-collector',
  source_slug:   'example-source',
  run_id:        `run_${Date.now()}`,
  started_at:    new Date().toISOString(),
};
console.log('[START]', JSON.stringify(ctx));
return [{ json: { _ctx: ctx } }];

// Simulates what a real collector returns — raw, unnormalized items.
// A real collector replaces ONLY this node.
const mockRaw = [
  {
